script:
frappe.ui.form.on('Land Unit', {
    refresh: function(frm) {
        if (frm.doc.gps_coordinates) {
            frm.trigger('render_map');
        } else if (frm.doc.location) {
            frappe.db.get_value('Location', frm.doc.location, ['latitude', 'longitude']).then(r => {
                if (r.message && r.message.latitude && r.message.longitude) {
                    frm.trigger('render_map_from_location');
                } else {
                    frm.fields_dict.map_html.$wrapper.html(
                        '<div class="alert alert-info">Enter GPS coordinates or link a Location to view the map.</div>'
                    );
                }
            });
        } else {
            frm.fields_dict.map_html.$wrapper.html(
                '<div class="alert alert-info">Enter GPS coordinates or link a Location to view the map.</div>'
            );
        }
    },
    render_map: function(frm) {
        let coords;
        try {
            coords = JSON.parse(frm.doc.gps_coordinates).features[0].geometry.coordinates;
        } catch (e) {
            return;
        }

        const map_id = 'map-' + frm.doc.name;
        frm.fields_dict.map_html.$wrapper.html(
            '<div id="' + map_id + '" style="height: 300px; width: 100%; border-radius: 8px;"></div>' +
            '<link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css" />'
        );

        function initMap() {
            setTimeout(function() {
                var map = L.map(map_id).setView([coords[1], coords[0]], 15);
                L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
                    maxZoom: 19,
                    attribution: '&copy; OpenStreetMap'
                }).addTo(map);
                L.marker([coords[1], coords[0]])
                    .addTo(map)
                    .bindPopup(frm.doc.land_unit_name)
                    .openPopup();
            }, 500);
        }

        if (typeof L === 'undefined') {
            var script = document.createElement('script');
            script.src = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js';
            script.onload = initMap;
            document.head.appendChild(script);
        } else {
            initMap();
        }
    },
    render_map_from_location: function(frm) {
        frappe.db.get_value('Location', frm.doc.location, ['latitude', 'longitude']).then(r => {
            if (!r.message) return;
            var lat = r.message.latitude;
            var lon = r.message.longitude;

            const map_id = 'map-' + frm.doc.name;
            frm.fields_dict.map_html.$wrapper.html(
                '<div id="' + map_id + '" style="height: 300px; width: 100%; border-radius: 8px;"></div>' +
                '<link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css" />'
            );

            function initMap() {
                setTimeout(function() {
                    var map = L.map(map_id).setView([lat, lon], 15);
                    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
                        maxZoom: 19,
                        attribution: '&copy; OpenStreetMap'
                    }).addTo(map);
                    L.marker([lat, lon])
                        .addTo(map)
                        .bindPopup(frm.doc.land_unit_name)
                        .openPopup();
                }, 500);
            }

            if (typeof L === 'undefined') {
                var script = document.createElement('script');
                script.src = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js';
                script.onload = initMap;
                document.head.appendChild(script);
            } else {
                initMap();
            }
        });
    }
});

frappe.ui.form.on('Labour Contract', {
    refresh: function(frm) {
        if (frm.doc.status === 'Active' && !frm.doc.journal_entry) {
            frm.add_custom_button(__('Create Journal Entry'), function() {
                frappe.call({
                    method: 'Make-Labour-Contract-Journal-Entry',
                    args: { contract_name: frm.doc.name },
                    callback: function(r) {
                        if (r.message) {
                            frappe.msgprint('Journal Entry created: ' + r.message);
                            frm.reload_doc();
                        }
                    }
                });
            });
        }
    }
});

frappe.ui.form.on('Labour Attendance', {
    hours_worked: function(frm, cdt, cdn) {
        var row = locals[cdt][cdn];
        if (row.hours_worked && row.pay_rate) {
            frappe.model.set_value(cdt, cdn, 'total_pay', row.hours_worked * row.pay_rate);
        }
        calculate_contract_totals(frm);
    },
    pay_rate: function(frm, cdt, cdn) {
        var row = locals[cdt][cdn];
        if (row.hours_worked && row.pay_rate) {
            frappe.model.set_value(cdt, cdn, 'total_pay', row.hours_worked * row.pay_rate);
        }
        calculate_contract_totals(frm);
    },
    attendance_remove: function(frm) {
        calculate_contract_totals(frm);
    }
});

function calculate_contract_totals(frm) {
    var total_hours = 0;
    var total_wage = 0;
    (frm.doc.attendance || []).forEach(function(row) {
        total_hours += flt(row.hours_worked);
        total_wage += flt(row.total_pay);
    });
    frm.set_value('total_hours', total_hours);
    frm.set_value('total_wage_bill', total_wage);
}

frappe.ui.form.on('Yield Map', {
    refresh: function(frm) {
        if (frm.doc.land_unit) {
            frm.trigger('render_yield_map');
        }
    },
    render_yield_map: function(frm) {
        frappe.db.get_doc('Land Unit', frm.doc.land_unit).then(function(lu) {
            var lat, lon;

            // Try gps_coordinates first
            if (lu.gps_coordinates) {
                try {
                    var coords = JSON.parse(lu.gps_coordinates).features[0].geometry.coordinates;
                    lon = coords[0];
                    lat = coords[1];
                } catch (e) {}
            }

            // Fallback to linked Location
            if (!lat && lu.location) {
                frappe.db.get_value('Location', lu.location, ['latitude', 'longitude']).then(r => {
                    if (r.message && r.message.latitude) {
                        render_map(frm, r.message.latitude, r.message.longitude, lu.land_unit_name);
                    }
                });
                return;
            }

            if (lat) {
                render_map(frm, lat, lon, lu.land_unit_name);
            }
        });
    }
});

function render_map(frm, lat, lon, name) {
    var map_id = 'yield-map-' + frm.doc.name;
    frm.fields_dict.map_html.$wrapper.html(
        '<div id="' + map_id + '" style="height: 400px; width: 100%; border-radius: 8px;"></div>' +
        '<link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css" />'
    );

    function initMap() {
        setTimeout(function() {
            var map = L.map(map_id).setView([lat, lon], 15);
            L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
                attribution: '&copy; OpenStreetMap'
            }).addTo(map);

            var radius = Math.min(frm.doc.total_harvest_qty / 10, 500);
            L.circle([lat, lon], {
                color: 'green',
                fillColor: '#28a745',
                fillOpacity: 0.5,
                radius: radius > 0 ? radius : 100
            }).addTo(map)
            .bindPopup(
                '<b>' + name + '</b><br>' +
                'Yield: ' + frm.doc.total_harvest_qty + ' units<br>' +
                'Acre Yield: ' + (frm.doc.yield_per_acre || 'N/A')
            );
        }, 500);
    }

    if (typeof L === 'undefined') {
        var script = document.createElement('script');
        script.src = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js';
        script.onload = initMap;
        document.head.appendChild(script);
    } else {
        initMap();
    }
}
